import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.DisplayName
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test
import org.junit.jupiter.params.ParameterizedTest
import org.junit.jupiter.params.provider.EnumSource

/**
 * Test cases for Issue 2028 - Do not merge annotated expression with function signature.
 *
 * When a function body expression starts with an annotation (e.g., @Suppress), the function-signature
 * rule should not merge it with the function signature as this would violate the annotation rule.
 */
class FunctionSignatureRuleAnnotatedExpressionTest {
    private val functionSignatureRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Nested
    @DisplayName("Given a function with an annotated expression body")
    inner class AnnotatedExpressionBody {

        @Test
        fun `Given a function with annotated expression body that fits on same line as signature then do not merge`() {
            // This is the original issue case
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER                                                                                       $EOL_CHAR
                private fun getErrorMessage(value: String): String =
                        @Suppress("DEPRECATION")
                        customMessage.takeUnless { it.isEmpty() } ?: String.format(DEFAULT_ERROR_MESSAGE_WITH_NO_REASON, value)
                """.trimIndent()

            // The rule should NOT emit a violation to merge the body with the signature
            // because the body starts with an annotation
            functionSignatureRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }

        @ParameterizedTest(name = "Code style: {0}")
        @EnumSource(CodeStyleValue::class)
        fun `Given a simple annotated expression that would fit on same line then do not merge`(codeStyle: CodeStyleValue) {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER                     $EOL_CHAR
                fun foo() =
                    @Suppress("UNCHECKED_CAST")
                    bar()
                """.trimIndent()

            functionSignatureRuleAssertThat(code)
                .setMaxLineLength()
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to codeStyle)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a multiline function signature with annotated expression body then do not merge`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER                                   $EOL_CHAR
                fun foo(
                    a: Int,
                    b: Int
                ) =
                    @Suppress("UNCHECKED_CAST")
                    bar(a, b)
                """.trimIndent()

            functionSignatureRuleAssertThat(code)
                .setMaxLineLength()
                .addAdditionalRuleProvider { IndentationRule() }
                .hasNoLintViolations()
        }

        @Test
        fun `Given a function with annotated expression body with multiple annotations then do not merge`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER                                            $EOL_CHAR
                fun foo() =
                    @Suppress("DEPRECATION")
                    @SomeOtherAnnotation
                    bar()
                """.trimIndent()

            functionSignatureRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }

        @Test
        fun `Given a function with annotated expression on same line as equals then do not change`() {
            // This is already on the same line, so it should be left as is
            // (although annotation rule might want to change it)
            val code =
                """
                fun foo() = @Suppress("UNCHECKED_CAST") bar()
                """.trimIndent()

            functionSignatureRuleAssertThat(code)
                .hasNoLintViolations()
        }
    }

    @Nested
    @DisplayName("Given a function with non-annotated expression body")
    inner class NonAnnotatedExpressionBody {

        @Test
        fun `Given a function with non-annotated expression body that fits on same line then merge`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER                  $EOL_CHAR
                fun f(
                    a: Any,
                    b: Any
                ) =
                    "some-result"
                """.trimIndent()

            val formattedCode =
                """
                // $MAX_LINE_LENGTH_MARKER                  $EOL_CHAR
                fun f(a: Any, b: Any) = "some-result"
                """.trimIndent()

            functionSignatureRuleAssertThat(code)
                .setMaxLineLength()
                .addAdditionalRuleProvider { IndentationRule() }
                .hasLintViolations(
                    com.pinterest.ktlint.test.LintViolation(3, 5, "No whitespace expected between opening parenthesis and first parameter name"),
                    com.pinterest.ktlint.test.LintViolation(4, 5, "Single whitespace expected before parameter"),
                    com.pinterest.ktlint.test.LintViolation(4, 11, "No whitespace expected between last parameter and closing parenthesis"),
                    com.pinterest.ktlint.test.LintViolation(5, 4, "First line of body expression fits on same line as function signature"),
                ).isFormattedAs(formattedCode)
        }
    }
}
"}

